1	/**
2	 * LayerInfinite MCP Server вҖ” index.ts
3	 * в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
4	 * V2 Gateway Proxy entry point. Uses low-level Server (ADR-001)
5	 * for raw JSON-RPC interception of tools/list and tools/call.
6	 *
7	 * Registers handlers:
8	 *   tools/list   вҖ” enriched upstream tools + virtual li_recommend
9	 *   tools/call   вҖ” proxy to upstream, auto-mode rerouting
10	 *   resources/*  вҖ” gateway status + config (admin-gated)
11	 *   prompts/*    вҖ” setup instructions
12	 * в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
13	 */
14	
15	import { Server } from '@modelcontextprotocol/sdk/server/index.js';
16	import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
17	import {
18	  CallToolRequestSchema,
19	  ListToolsRequestSchema,
20	} from '@modelcontextprotocol/sdk/types.js';
21	
22	import { loadConfig } from './config.js';
23	import type { GatewayConfig } from './config.js';
24	import { LiApiClient, UpstreamMCPClient } from './rest-client.js';
25	import { UpstreamRegistry } from './upstream-registry.js';
26	import { GatewayProxy } from './gateway-proxy.js';
27	import { OutcomeClassifier } from './outcome-classifier.js';
28	import { DecisionTracker } from './decision-tracker.js';
29	import { startQueueProcessor } from './fail-open.js';
30	import type { QueueSender } from './fail-open.js';
31	import type { OutcomePayload } from './types.js';
32	import { logger } from './logger.js';
33	import { dashboardResource } from './resources/dashboard.js';
34	import { docsResource } from './resources/docs.js';
35	import { onboardingPrompt } from './prompts/onboarding.js';
36	
37	const SERVER_NAME = 'layerinfinite-gateway';
38	const SERVER_VERSION = '2.0.0';
39	
40	const log = logger.forTool('index');
41	
42	// в”Җв”Җ Task context extraction в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
43	
44	interface TaskContext {
45	  taskType: string;
46	  customerId: string;
47	  agentId: string;
48	}
49	
50	function extractTaskContext(params: Record<string, unknown> | undefined): TaskContext {
51	  const args = (params?.['arguments'] as Record<string, unknown>) ?? {};
52	  const meta = (params?.['_meta'] as Record<string, unknown>) ?? {};
53	
54	  const taskType = String(
55	    args['task_type'] ?? args['taskType'] ?? params?.['task_type'] ?? meta['taskType'] ?? 'unknown',
56	  );
57	
58	  const customerId = String(
59	    args['customer_id'] ??
60	      args['customerId'] ??
61	      params?.['customer_id'] ??
62	      process.env.LAYERINFINITE_DEFAULT_CUSTOMER ??
63	      'default',
64	  );
65	
66	  const agentId = String(
67	    meta['agentId'] ??
68	      args['agent_id'] ??
69	      args['agentId'] ??
70	      params?.['agent_id'] ??
71	      process.env.LAYERINFINITE_DEFAULT_AGENT ??
72	      'unknown',
73	  );
74	
75	  return { taskType, customerId, agentId };
76	}
77	
78	// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
79	// createGatewayServer
80	// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
81	
82	export interface GatewayServer {
83	  server: Server;
84	  proxy: GatewayProxy;
85	  config: GatewayConfig;
86	  upstreamClient: UpstreamMCPClient;
87	  registry: UpstreamRegistry;
88	  tracker: DecisionTracker;
89	  queueProcessor: { stop: () => void };
90	}
91	
92	export function createGatewayServer(): GatewayServer {
93	  const config = loadConfig();
94	  const registry = new UpstreamRegistry(config);
95	  const liApi = new LiApiClient(config);
96	  const upstreamClient = new UpstreamMCPClient(registry);
97	
98	  const classifier = config.classifier ? new OutcomeClassifier(config.classifier) : null;
99	  const tracker = new DecisionTracker(liApi, config.environment);
100	  const proxy = new GatewayProxy(liApi, upstreamClient, registry, config, classifier, tracker);
101	
102	  // Start periodic queue processor for retrying failed outcome logs
103	  const queueSender: QueueSender = (payload: OutcomePayload) => liApi.logOutcome(payload);
104	  const queueProcessor = startQueueProcessor(queueSender, 30_000);
105	
106	  // Start periodic flush of tracker buffer (secondary durability)
107	  tracker.startFlushTimer();
108	
109	  const server = new Server(
110	    { name: SERVER_NAME, version: SERVER_VERSION },
111	    { capabilities: { tools: {}, resources: {}, prompts: {} } },
112	  );
113	
114	  const startedAt = Date.now();
115	
116	  // в”Җв”Җ tools/list в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
117	
118	  server.setRequestHandler(ListToolsRequestSchema, async (request) => {
119	    try {
120	      const taskCtx = extractTaskContext(request.params as Record<string, unknown> | undefined);
121	      const enriched = await proxy.handleListTools(taskCtx);
122	
123	      // Strip internal fields (upstreamName, annotations) per MCP spec
124	      const tools = enriched.map((t) => ({
125	        name: t.name,
126	        description: t.description,
127	        inputSchema: t.inputSchema,
128	      }));
129	
130	      return { tools };
131	    } catch (err) {
132	      log.error('tools/list handler failed', {
133	        error: err instanceof Error ? err.message : String(err),
134	      });
135	      return { tools: [] };
136	    }
137	  });
138	
139	  // в”Җв”Җ tools/call в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
140	
141	  server.setRequestHandler(CallToolRequestSchema, async (request) => {
142	    const toolName = request.params?.name ?? '';
143	    const args = (request.params?.arguments ?? {}) as Record<string, unknown>;
144	    const taskCtx = extractTaskContext(request.params as Record<string, unknown> | undefined);
145	
146	    try {
147	      const result = await proxy.handleCallTool(toolName, args, taskCtx);
148	      return result as unknown as { content: Array<{ type: string; text?: string }>; isError?: boolean };
149	    } catch (err) {
150	      const message = err instanceof Error ? err.message : String(err);
151	      log.error('tools/call handler failed', { tool: toolName, error: message });
152	      return {
153	        content: [{ type: 'text' as const, text: message }],
154	        isError: true,
155	      };
156	    }
157	  });
158	
159	  // в”Җв”Җ resources/list в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
160	
161	  server.setRequestHandler(
162	    { method: 'resources/list' } as never,
163	    async () => {
164	      try {
165	        const entries = registry.getAllUpstreams();
166	        const healthyCount = entries.filter((e) => registry.isHealthy(e.server.name)).length;
167	
168	        const resources = [
169	          {
170	            uri: 'li://gateway/status',
171	            name: 'Gateway Status',
172	            description: 'LayerInfinite Gateway Proxy runtime status',
173	            mimeType: 'text/plain',
174	          },
175	        ];
176	
177	        if (config.adminKey) {
178	          resources.push({
179	            uri: 'li://gateway/config',
180	            name: 'Gateway Configuration',
181	            description: 'Gateway config summary (requires admin key to read)',
182	            mimeType: 'application/json',
183	          });
184	        }
185	
186	          resources.push({ uri: dashboardResource.uri, name: dashboardResource.name, description: dashboardResource.description, mimeType: dashboardResource.mimeType });
187	          resources.push({ uri: docsResource.uri, name: docsResource.name, description: docsResource.description, mimeType: docsResource.mimeType });
188	
189	        return { resources };
190	      } catch (err) {
191	        log.error('resources/list failed', { error: err instanceof Error ? err.message : String(err) });
192	        return { resources: [] };
193	      }
194	    },
195	  );
196	
197	  // в”Җв”Җ resources/read в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
198	
199	  server.setRequestHandler(
200	    { method: 'resources/read' } as never,
201	    async (request: { params?: { uri?: string } }) => {
202	      const uri = request.params?.uri ?? '';
203	
204	      try {
205	        if (uri === 'li://gateway/status') {
206	          const entries = registry.getAllUpstreams();
207	          const healthy = entries.filter((e) => registry.isHealthy(e.server.name));
208	          const uptimeMs = Date.now() - startedAt;
209	
210	          const status = {
211	            mode: config.mode ?? 'bootstrap',
212	            environment: config.environment,
213	            shadowMode: config.shadowMode,
214	            upstreams: {
215	              total: entries.length,
216	              healthy: healthy.length,
217	              names: entries.map((e) => e.server.name),
218	              healthyNames: healthy.map((e) => e.server.name),
219	            },
220	            uptime_seconds: Math.floor(uptimeMs / 1000),
221	            version: SERVER_VERSION,
222	          };
223	
224	          return {
225	            contents: [
226	              {
227	                uri,
228	                mimeType: 'text/plain',
229	                text: JSON.stringify(status, null, 2),
230	              },
231	            ],
232	          };
233	        }
234	
235	        if (uri === 'li://gateway/config') {
236	          return {
237	            contents: [
238	              {
239	                uri,
240	                mimeType: 'application/json',
241	                text: JSON.stringify(
242	                  {
243	                    mode: config.mode ?? 'bootstrap',
244	                    environment: config.environment,
245	                    shadowMode: config.shadowMode,
246	                    upstreamCount: config.upstreamServers.length,
247	                    modeOverrides: Object.fromEntries(config.modeOverrides),
248	                    apiKey: '[REDACTED]',
249	                    baseUrl: config.baseUrl,
250	                    adminEnabled: config.adminKey !== null,
251	                  },
252	                  null,
253	                  2,
254	                ),
255	              },
256	            ],
257	          };
258	        }
259	
260	          if (uri === dashboardResource.uri) {
261	            const result = await dashboardResource.handler();
262	            return { contents: result.contents };
263	          }
264	
265	          if (uri === docsResource.uri) {
266	            const result = await docsResource.handler();
267	            return { contents: result.contents };
268	          }
269	
270	        return {
271	          contents: [
272	            {
273	              uri,
274	              mimeType: 'text/plain',
275	              text: `Unknown resource: ${uri}`,
276	            },
277	          ],
278	        };
279	      } catch (err) {
280	        log.error('resources/read failed', { uri, error: err instanceof Error ? err.message : String(err) });
281	        return {
282	          contents: [{ uri, mimeType: 'text/plain', text: 'Error reading resource' }],
283	        };
284	      }
285	    },
286	  );
287	
288	  // в”Җв”Җ prompts/list в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
289	
290	  server.setRequestHandler(
291	    { method: 'prompts/list' } as never,
292	    async () => {
293	      return {
294	        prompts: [
295	          {
296	            name: 'layerinfinite-gateway-setup',
297	            description: 'LayerInfinite Gateway Proxy setup instructions',
298	            arguments: [],
299	          },
300	          {
301	            name: onboardingPrompt.name,
302	            description: onboardingPrompt.description,
303	            arguments: onboardingPrompt.arguments,
304	          },
305	        ],
306	      };
307	    },
308	  );
309	
310	  // в”Җв”Җ prompts/get в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
311	
312	  server.setRequestHandler(
313	    { method: 'prompts/get' } as never,
314	    async (request: { params?: { name?: string; arguments?: Record<string, unknown> } }) => {
315	      const name = request.params?.name ?? '';
316	
317	      if (name === onboardingPrompt.name) {
318	          const result = await onboardingPrompt.handler();
319	          return { messages: result.messages };
320	        }
321	
322	        if (name !== 'layerinfinite-gateway-setup') {
323	        return {
324	          messages: [
325	            {
326	              role: 'user' as const,
327	              content: { type: 'text' as const, text: `Unknown prompt: ${name}` },
328	            },
329	          ],
330	        };
331	      }
332	
333	      const text = [
334	        '# LayerInfinite Gateway Proxy Setup',
335	        '',
336	        'The LayerInfinite MCP Gateway Proxy transparently enriches your existing MCP tools with historical outcome intelligence.',
337	        '',
338	        '## Configuration',
339	        '',
340	        'Set these environment variables before starting:',
341	        '',
342	        '| Variable | Required | Description |',
343	        '|----------|----------|-------------|',
344	        '| `LAYERINFINITE_API_KEY` | Yes | Your LayerInfinite API key |',
345	        '| `LAYERINFINITE_UPSTREAM_TOOLS` | Yes | JSON array of upstream MCP servers (name, url, optional apiKey) |',
346	        '| `LAYERINFINITE_MODE` | No | Operating mode: `recommend`, `assist`, `auto` (omit for bootstrap) |',
347	        '| `LAYERINFINITE_MODE_OVERRIDES` | No | Per-task-type mode overrides as JSON object |',
348	        '| `LAYERINFINITE_SHADOW_MODE` | No | Set to `true` to observe without intervening |',
349	        '| `LAYERINFINITE_ENVIRONMENT` | No | `staging` or `production` (default: production) |',
350	        '| `LAYERINFINITE_BASE_URL` | No | API base URL (default: https://layerinfinite.me) |',
351	        '',
352	        '## Modes',
353	        '',
354	        '- **Bootstrap** (no mode set): Observe only вҖ” no enrichment or intervention',
355	        '- **Recommend**: Tool descriptions enriched with historical success rates',
356	        '- **Assist**: Recommendations + directional warnings based on history',
357	        '- **Auto**: Silent rerouting to the best tool based on outcome data',
358	        '',
359	        '## Upstream Format',
360	        '',
361	        '```json',
362	        '[',
363	        '  { "name": "github", "url": "https://github-mcp.example.com", "apiKey": "sk-..." },',
364	        '  { "name": "filesystem", "url": "http://localhost:8080" }',
365	        ']',
366	        '```',
367	        '',
368	        '## Starting the Gateway',
369	        '',
370	        '```bash',
371	        'npx @layerinfinite/mcp-server',
372	        '# or directly:',
373	        'node dist/bin/cli.js',
374	        '```',
375	        '',
376	        'The gateway connects via stdio вҖ” configure your MCP client to spawn this process.',
377	      ].join('\n');
378	
379	      return {
380	        messages: [
381	          {
382	            role: 'user' as const,
383	            content: { type: 'text' as const, text },
384	          },
385	        ],
386	      };
387	    },
388	  );
389	
390	  log.info('Gateway server created', {
391	    mode: config.mode ?? 'bootstrap',
392	    upstreams: config.upstreamServers.length,
393	    environment: config.environment,
394	    shadowMode: config.shadowMode,
395	    classifier: config.classifier ? `${config.classifier.model} (enabled)` : 'disabled',
396	  });
397	
398	  return { server, proxy, config, upstreamClient, registry, tracker, queueProcessor };
399	}
400	
401

1	/**
2	 * LayerInfinite MCP Server вҖ” upstream-registry.ts
3	 * в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
4	 * Manages upstream MCP server connections: registration, health
5	 * checks, circuit breaker integration, and tool discovery.
6	 * в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
7	 */
8	
9	import type { UpstreamServer, GatewayConfig } from './config.js';
10	import {
11	  createFailOpenState,
12	  recordUpstreamFailure,
13	  recordUpstreamSuccess,
14	  probeCircuitBreaker,
15	  updateHealthCheck,
16	  isCircuitOpen,
17	} from './fail-open.js';
18	import type { FailOpenState } from './types.js';
19	import { logger } from './logger.js';
20	
21	const log = logger.forTool('upstream-registry');
22	
23	const DEFAULT_HEALTH_CHECK_MS = 30_000;
24	const HEALTH_PING_TIMEOUT_MS = 5_000;
25	
26	export interface UpstreamEntry {
27	  server: UpstreamServer;
28	  healthy: boolean;
29	  lastCheck: number;
30	  lastError?: string;
31	}
32	
33	export class UpstreamRegistry {
34	  private readonly servers: Map<string, UpstreamEntry> = new Map();
35	  private readonly state: FailOpenState;
36	  private healthCheckTimer: ReturnType<typeof setInterval> | null = null;
37	  private shutdownFlag = false;
38	
39	  constructor(config: GatewayConfig) {
40	    this.state = createFailOpenState();
41	    for (const server of config.upstreamServers) {
42	      this.servers.set(server.name, {
43	        server,
44	        healthy: true, // Start optimistic вҖ” first health check will correct
45	        lastCheck: 0,
46	      });
47	      log.info('Registered upstream', { name: server.name, url: server.url });
48	    }
49	  }
50	
51	  /** Get a single upstream by name. */
52	  getUpstream(name: string): UpstreamEntry | undefined {
53	    return this.servers.get(name);
54	  }
55	
56	  /** Get all upstream server configs. */
57	  getAllUpstreams(): UpstreamEntry[] {
58	    return Array.from(this.servers.values());
59	  }
60	
61	  /** Check if an upstream is healthy (circuit closed + recent health check OK). */
62	  isHealthy(name: string): boolean {
63	    const entry = this.servers.get(name);
64	    if (!entry) return false;
65	    if (isCircuitOpen(this.state, name)) return false;
66	    return entry.healthy;
67	  }
68	
69	  /** Get the FailOpenState for external circuit breaker queries. */
70	  getFailOpenState(): FailOpenState {
71	    return this.state;
72	  }
73	
74	  /**
75	   * Start periodic health checks for all upstream servers.
76	   * Each upstream gets its own check interval (default 30s).
77	   */
78	  startHealthChecks(): void {
79	    if (this.healthCheckTimer) return;
80	
81	    // Run initial checks immediately
82	    void this.checkAllUpstreams();
83	
84	    this.healthCheckTimer = setInterval(() => {
85	      if (this.shutdownFlag) return;
86	      void this.checkAllUpstreams();
87	    }, DEFAULT_HEALTH_CHECK_MS);
88	
89	    log.info('Health checks started', { upstreams: this.servers.size });
90	  }
91	
92	  /** Stop the health check loop. */
93	  stopHealthChecks(): void {
94	    this.shutdownFlag = true;
95	    if (this.healthCheckTimer) {
96	      clearInterval(this.healthCheckTimer);
97	      this.healthCheckTimer = null;
98	      log.info('Health checks stopped');
99	    }
100	  }
101	
102	  private async checkAllUpstreams(): Promise<void> {
103	    const checks = Array.from(this.servers.values()).map((entry) =>
104	      this.checkUpstream(entry),
105	    );
106	    await Promise.allSettled(checks);
107	  }
108	
109	  private async checkUpstream(entry: UpstreamEntry): Promise<void> {
110	    const { server } = entry;
111	    const interval = server.healthCheckIntervalMs ?? DEFAULT_HEALTH_CHECK_MS;
112	
113	    // Skip if checked recently
114	    if (Date.now() - entry.lastCheck < interval) return;
115	
116	    // Check if circuit breaker allows probing
117	    probeCircuitBreaker(this.state, server.name);
118	    updateHealthCheck(this.state, server.name);
119	
120	    try {
121	      const controller = new AbortController();
122	      const timeout = setTimeout(() => controller.abort(), HEALTH_PING_TIMEOUT_MS);
123	
124	      const response = await fetch(`${server.url}/health`, {
125	        method: 'GET',
126	        headers: server.apiKey
127	          ? { Authorization: `Bearer ${server.apiKey}` }
128	          : {},
129	        signal: controller.signal,
130	      });
131	
132	      clearTimeout(timeout);
133	
134	      if (response.ok) {
135	        entry.healthy = true;
136	        entry.lastCheck = Date.now();
137	        entry.lastError = undefined;
138	        recordUpstreamSuccess(this.state, server.name);
139	        log.debug('Upstream healthy', { name: server.name });
140	      } else {
141	        entry.healthy = false;
142	        entry.lastCheck = Date.now();
143	        entry.lastError = `HTTP ${response.status}`;
144	        recordUpstreamFailure(this.state, server.name);
145	        log.warn('Upstream unhealthy', {
146	          name: server.name,
147	          status: response.status,
148	        });
149	      }
150	    } catch (err) {
151	      entry.healthy = false;
152	      entry.lastCheck = Date.now();
153	      entry.lastError = err instanceof Error ? err.message : String(err);
154	      recordUpstreamFailure(this.state, server.name);
155	      log.warn('Upstream health check failed', {
156	        name: server.name,
157	        error: entry.lastError,
158	      });
159	    }
160	  }
161	}
