84	export class LiApiClient {
85	  private readonly baseUrl: string;
86	  private readonly primaryKey: string;
87	  private readonly secondaryKey: string | undefined;
88	
89	  constructor(config: GatewayConfig) {
90	    this.baseUrl = config.baseUrl;
91	    this.primaryKey = config.apiKey;
92	    this.secondaryKey = config.apiKeySecondary;
93	  }
94	
95	  private buildHeaders(apiKey?: string): Record<string, string> {
96	    return {
97	      'X-API-Key': apiKey ?? this.primaryKey,
98	      'Content-Type': 'application/json',
99	      'User-Agent': '@layerinfinite/mcp-server/2.0.0',
100	    };
101	  }
102	
103	  /** Fetch scored actions for a task type. */
104	  async getScores(
105	    taskType: string,
106	    customerId: string,
107	    agentId: string,
108	  ): Promise<ScoredAction[]> {
109	    const result = await this.get<{ scores: ScoredAction[] }>(
110	      '/v1/get-scores',
111	      { task_type: taskType, customer_id: customerId, agent_id: agentId },
112	    );
113	    if (!result.ok) {
114	      log.warn('getScores failed', { code: result.error.code });
115	      return [];
116	    }
117	    return result.data.scores ?? [];
118	  }
119	
120	  /** Fetch policy decision for a task type. */
121	  async getPolicyDecision(
122	    taskType: string,
123	    customerId: string,
124	    agentId: string,
125	  ): Promise<PolicyDecision | null> {
126	    const result = await this.get<{ decision: PolicyDecision | null }>(
127	      '/v1/recommendations',
128	      { task_type: taskType, customer_id: customerId, agent_id: agentId },
129	    );
130	    if (!result.ok) {
131	      log.warn('getPolicyDecision failed', { code: result.error.code });
132	      return null;
133	    }
134	    return result.data.decision ?? null;
135	  }
136	
137	  /** Fire-and-forget outcome logging. Returns true if successful. */
138	  async logOutcome(payload: OutcomePayload): Promise<boolean> {
139	    const result = await this.post<{ accepted: boolean }>(
140	      '/v1/log-outcome',
141	      payload as unknown as Record<string, unknown>,
142	    );
143	    return result.ok;
