146	  /** Get recommendations for a task type (legacy / li_recommend support). */
147	  async getRecommendations(
148	    taskType: string,
149	    customerId: string,
150	    agentId: string,
151	  ): Promise<ScoredAction[]> {
152	    return this.getScores(taskType, customerId, agentId);
153	  }
154	
155	  // в”Җв”Җ HTTP helpers (preserved from V1) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
156	
157	  private async get<T>(
158	    path: string,
159	    params?: Record<string, string>,
160	  ): Promise<LIResult<T>> {
161	    const url = new URL(`${this.baseUrl}${path}`);
162	    if (params) {
163	      for (const [key, value] of Object.entries(params)) {
164	        if (value !== undefined && value !== '') {
165	          url.searchParams.set(key, value);
166	        }
167	      }
168	    }
169	    return this.requestWithRetry<T>(url.toString(), { method: 'GET' });
170	  }
171	
172	  private async post<T>(
173	    path: string,
174	    body: Record<string, unknown>,
175	  ): Promise<LIResult<T>> {
176	    return this.requestWithRetry<T>(`${this.baseUrl}${path}`, {
177	      method: 'POST',
178	      body: JSON.stringify(body),
179	    });
180	  }
181	
182	  private async requestWithRetry<T>(
183	    url: string,
184	    init: RequestInit,
185	  ): Promise<LIResult<T>> {
186	    let lastResult: LIResult<T> | null = null;
187	
188	    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
189	      if (attempt > 0) {
190	        const delay = BASE_RETRY_DELAY_MS * Math.pow(2, attempt - 1);
191	        log.warn('Retrying LI API request', { url, attempt: attempt + 1, delay_ms: delay });
192	        await this.sleep(delay);
193	      }
194	
195	      const result = await this.request<T>(url, init);
196	      if (result.ok) return result;
197	
198	      lastResult = result;
199	      const isRetryable = RETRYABLE_STATUS_CODES.has(result.status)
200	        || result.error.code === 'TIMEOUT'
201	        || result.error.code === 'NETWORK_ERROR';
202	      if (!isRetryable) break;
203	    }
204	
205	    return lastResult!;
206	  }
207	
208	  private async request<T>(
209	    url: string,
210	    init: RequestInit,
211	    usedSecondary = false,
212	  ): Promise<LIResult<T>> {
213	    const controller = new AbortController();
214	    const timeout = setTimeout(() => controller.abort(), LI_API_TIMEOUT_MS);
215	    const startMs = Date.now();
216	
217	    try {
218	      const response = await fetch(url, {
219	        ...init,
220	        headers: { ...this.buildHeaders(), ...(init.headers as Record<string, string> ?? {}) },
221	        signal: controller.signal,
222	      });
223	
224	      const latencyMs = Date.now() - startMs;
225	      const isJson = response.headers.get('content-type')?.includes('application/json');
226	
227	      if (response.ok) {
228	        const data = isJson ? (await response.json()) as T : ({} as T);
229	        log.debug('LI API response', { method: init.method, url, status: response.status, latency_ms: latencyMs });
230	        return { ok: true, status: response.status, data };
231	      }
232	
233	      // Zero-downtime key rotation: retry with secondary key on auth failure
234	      if ((response.status === 401 || response.status === 403) && this.secondaryKey && !usedSecondary) {
235	        clearTimeout(timeout);
236	        log.info('Primary key rejected вҖ” retrying with secondary key');
237	        return this.request<T>(url, {
238	          ...init,
239	          headers: { ...this.buildHeaders(this.secondaryKey), ...(init.headers as Record<string, string> ?? {}) },
240	        }, true);
241	      }
242	
243	      const errorBody: LIApiError = isJson
244	        ? (await response.json()) as LIApiError
245	        : { error: 'API Error', code: 'UNKNOWN', message: await response.text() };
246	
247	      log.warn('LI API error', { method: init.method, url, status: response.status, error_code: errorBody.code });
248	      return { ok: false, status: response.status, error: errorBody };
249	    } catch (err) {
250	      const latencyMs = Date.now() - startMs;
251	      if (err instanceof DOMException && err.name === 'AbortError') {
252	        log.error('LI API timeout', { method: init.method, url, timeout_ms: LI_API_TIMEOUT_MS });
253	        return {
254	          ok: false,
255	          status: 0,
256	          error: { error: 'Request timed out', code: 'TIMEOUT', message: `Request timed out after ${LI_API_TIMEOUT_MS}ms` },
257	        };
258	      }
259	
260	      const message = err instanceof Error ? err.message : String(err);
261	      log.error('LI API network error', { method: init.method, url, error: message });
262	      return {
263	        ok: false,
264	        status: 0,
265	        error: { error: 'Network error', code: 'NETWORK_ERROR', message },
266	      };
267	    } finally {
268	      clearTimeout(timeout);
269	    }
270	  }
271	
272	  private sleep(ms: number): Promise<void> {
273	    return new Promise((resolve) => setTimeout(resolve, ms));
274	  }
275	}
