277	// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
278	// UpstreamMCPClient вҖ” MCP JSON-RPC proxy to upstream servers
279	// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
280	
281	export class UpstreamMCPClient {
282	  private readonly registry: UpstreamRegistry;
283	  private readonly failOpenState: FailOpenState;
284	  private readonly sessions = new Map<string, string>();
285	  private requestCounter = 0;
286	  private readonly activeConnections = new Map<string, number>();
287	  private readonly maxConcurrent: number;
288	  private readonly initialized = new Map<string, boolean>();
289	  private readonly initPromises = new Map<string, Promise<void>>();
290	
291	  constructor(registry: UpstreamRegistry) {
292	    this.registry = registry;
293	    this.failOpenState = registry.getFailOpenState();
294	    this.maxConcurrent = getMaxConcurrentUpstream();
295	  }
296	
297	  /** Fetch all tools from all healthy upstreams. */
298	  async listTools(): Promise<RawUpstreamTool[]> {
299	    const tools: RawUpstreamTool[] = [];
300	    const healthy = this.getHealthyUpstreams();
301	    const entries = this.registry.getAllUpstreams().filter((e) => healthy.includes(e.server.name));
302	
303	    const results = await Promise.allSettled(
304	      entries.map(async (entry) => {
305	        const rawTools = await this.fetchUpstreamTools(entry.server);
306	        return rawTools.map((t) => ({
307	          ...t,
308	          upstreamName: entry.server.name,
309	        }));
310	      }),
311	    );
312	
313	    for (const result of results) {
314	      if (result.status === 'fulfilled') {
315	        tools.push(...result.value);
316	      }
317	    }
318	
319	    return tools;
320	  }
321	
322	  /** Call a tool on a specific upstream server. */
323	  async callTool(
324	    upstreamName: string,
325	    toolName: string,
326	    args: Record<string, unknown>,
327	  ): Promise<UpstreamCallResult> {
328	    const entry = this.registry.getUpstream(upstreamName);
329	    if (!entry) {
330	      throw new Error(`Upstream "${upstreamName}" not found`);
331	    }
332	
333	    await this.ensureInitialized(entry.server);
334	
335	    try {
336	      const result = await this.mcpRequest<UpstreamCallResult>(
337	        entry.server,
338	        'tools/call',
339	        { name: toolName, arguments: args },
340	      );
341	      recordUpstreamSuccess(this.failOpenState, upstreamName);
342	      return result;
343	    } catch (err) {
344	      recordUpstreamFailure(this.failOpenState, upstreamName);
345	      throw err;
346	    }
347	  }
348	
349	  /** Get list of healthy upstream names (circuit closed + last health check OK). */
350	  getHealthyUpstreams(): string[] {
351	    return this.registry.getAllUpstreams()
352	      .filter((e) => this.registry.isHealthy(e.server.name))
353	      .map((e) => e.server.name);
354	  }
355	
356	  /** Start periodic health checks on all upstreams. */
357	  startHealthChecks(): void {
358	    this.registry.startHealthChecks();
359	  }
360	
361	  /** Stop periodic health checks. */
362	  stopHealthChecks(): void {
363	    this.registry.stopHealthChecks();
364	  }
365	
366	  // в”Җв”Җ Private: MCP JSON-RPC в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
367	
368	  private async ensureInitialized(server: UpstreamServer): Promise<void> {
369	    if (this.initialized.get(server.name)) return;
370	
371	    const existing = this.initPromises.get(server.name);
372	    if (existing) return existing;
373	
374	    const promise = this.doInitialize(server);
375	    this.initPromises.set(server.name, promise);
376	
377	    try {
378	      await promise;
379	    } finally {
380	      this.initPromises.delete(server.name);
381	    }
382	  }
383	
384	  private async doInitialize(server: UpstreamServer): Promise<void> {
385	    const body = JSON.stringify({
386	      jsonrpc: '2.0',
387	      method: 'initialize',
388	      params: {
389	        protocolVersion: '2024-11-05',
390	        capabilities: {},
391	        clientInfo: { name: 'layerinfinite-gateway', version: '2.0.0' },
392	      },
393	      id: 0,
394	    });
395	
396	    const headers: Record<string, string> = {
397	      'Content-Type': 'application/json',
398	      Accept: 'application/json',
399	    };
400	    if (server.apiKey) headers['Authorization'] = `Bearer ${server.apiKey}`;
401	
402	    const response = await fetch(server.url, {
403	      method: 'POST',
404	      headers,
405	      body,
406	      signal: AbortSignal.timeout(10_000),
407	    });
408	
409	    if (!response.ok) {
410	      throw new Error(`Initialize failed for ${server.name}: HTTP ${response.status}`);
411	    }
412	
413	    const sessionId = response.headers.get('Mcp-Session-Id');
414	    if (sessionId) {
415	      this.sessions.set(server.name, sessionId);
416	    }
417	
418	    // Send initialized notification (no id = notification per MCP spec)
419	    const notifBody = JSON.stringify({
420	      jsonrpc: '2.0',
421	      method: 'notifications/initialized',
422	      params: {},
423	    });
424	
425	    const notifHeaders: Record<string, string> = { 'Content-Type': 'application/json' };
426	    if (sessionId) notifHeaders['Mcp-Session-Id'] = sessionId;
427	    if (server.apiKey) notifHeaders['Authorization'] = `Bearer ${server.apiKey}`;
428	
429	    await fetch(server.url, {
430	      method: 'POST',
431	      headers: notifHeaders,
432	      body: notifBody,
433	      signal: AbortSignal.timeout(5_000),
434	    });
435	
436	    this.initialized.set(server.name, true);
437	    log.info('Upstream initialized', { name: server.name });
438	  }
439	
440	  private async fetchUpstreamTools(server: UpstreamServer): Promise<Omit<RawUpstreamTool, 'upstreamName'>[]> {
441	    await this.ensureInitialized(server);
442	    const result = await this.mcpRequest<{ tools: Array<{ name: string; description: string; inputSchema: Record<string, unknown> }> }>(
443	      server,
444	      'tools/list',
445	    );
446	    return (result.tools ?? []).map((t) => ({
447	      name: t.name,
448	      description: t.description ?? '',
449	      inputSchema: t.inputSchema ?? { type: 'object', properties: {} },
450	    }));
451	  }
452	
453	  private async mcpRequest<T>(
454	    server: UpstreamServer,
455	    method: string,
456	    params?: Record<string, unknown>,
457	  ): Promise<T> {
458	    // в”Җв”Җ Concurrency gate в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
459	    const active = this.activeConnections.get(server.name) ?? 0;
460	    if (active >= this.maxConcurrent) {
461	      throw new Error(
462	        `Upstream "${server.name}" concurrency limit reached (${active}/${this.maxConcurrent})`,
463	      );
464	    }
465	    this.activeConnections.set(server.name, active + 1);
466	
467	    const id = ++this.requestCounter;
468	    const body = JSON.stringify({
469	      jsonrpc: '2.0',
470	      method,
471	      params: params ?? {},
472	      id,
473	    });
474	
475	    const headers: Record<string, string> = {
476	      'Content-Type': 'application/json',
477	      Accept: 'application/json',
478	    };
479	
480	    if (server.apiKey) {
481	      headers['Authorization'] = `Bearer ${server.apiKey}`;
482	    }
483	
484	    const sessionId = this.sessions.get(server.name);
485	    if (sessionId) {
486	      headers['Mcp-Session-Id'] = sessionId;
487	    }
488	
489	    const controller = new AbortController();
490	    const timeout = setTimeout(() => controller.abort(), MCP_CALL_TIMEOUT_MS);
491	
492	    try {
493	      const response = await fetch(server.url, {
494	        method: 'POST',
495	        headers,
496	        body,
497	        signal: controller.signal,
498	      });
499	
500	      // Cache session ID from response
501	      const newSessionId = response.headers.get('Mcp-Session-Id');
502	      if (newSessionId) {
503	        this.sessions.set(server.name, newSessionId);
504	      }
505	
506	      const contentType = response.headers.get('content-type') ?? '';
507	
508	      if (!response.ok) {
509	        const text = await response.text().catch(() => '');
510	        throw new Error(`Upstream ${server.name} returned HTTP ${response.status}: ${text.slice(0, 200)}`);
511	      }
512	
513	      // Handle non-JSON responses gracefully
514	      if (!contentType.includes('application/json') && !contentType.includes('text/plain')) {
515	        const text = await response.text();
516	        log.warn('Non-JSON upstream response', { server: server.name, method, contentType });
517	        // Try to parse as JSON anyway
518	        try {
519	          const data = JSON.parse(text);
520	          if (data.error) {
521	            throw new Error(`MCP error from ${server.name}: ${data.error.message ?? JSON.stringify(data.error)}`);
522	          }
523	          return data.result as T;
524	        } catch {
525	          // If it's not JSON at all, return as text content
526	          return { content: [{ type: 'text', text }] } as unknown as T;
527	        }
528	      }
529	
530	      const data = (await response.json()) as { error?: { message?: string }; result?: T };
531	
532	      if (data.error) {
533	        throw new Error(`MCP error from ${server.name}: ${data.error.message ?? JSON.stringify(data.error)}`);
534	      }
535	
536	      return data.result as T;
537	    } catch (err) {
538	      if (err instanceof DOMException && err.name === 'AbortError') {
539	        throw new Error(`Upstream ${server.name} timed out after ${MCP_CALL_TIMEOUT_MS}ms`);
540	      }
541	      throw err;
542	    } finally {
543	      clearTimeout(timeout);
544	      // Release concurrency slot
545	      const cur = this.activeConnections.get(server.name) ?? 1;
546	      if (cur <= 1) {
547	        this.activeConnections.delete(server.name);
548	      } else {
549	        this.activeConnections.set(server.name, cur - 1);
550	      }
551	    }
552	  }
553	}
